const input = $json.blog_comp;
const output = {};

input.forEach((item, index) => {
  output[`blog_comp_${index + 1}`] = {
    topic: item.Topic || "",
    keywords: item.Keywords || "",
    summary: item.Summary || ""
  };
});

return [{ json: output }];

const input = $json.blog_main;
const output = {};

input.forEach((item, index) => {
  output[`blog_main_${index + 1}`] = {
    topic: item.Topic || "",
    keywords: item.Keywords || "",
    summary: item.Summary || ""
  };
});

return [{ json: output }];

for (const item of $input.all()) {
  let raw = item.json.output;
  raw = raw.replace(/```json/g, '').replace(/```/g, '').trim();
  let parsed;
  try {
    parsed = JSON.parse(raw);
  } catch (e) {
    parsed = raw;
  }
  item.json.output = parsed;
}

return $input.all();

